CREATE TABLE IF NOT EXISTS `student_iot_learning` (
    `attendance_rate` TEXT COMMENT 'attendance_rate',
    `interaction_count` TEXT COMMENT 'interaction_count',
    `engagement_score` TEXT COMMENT 'engagement_score',
    `lms_login_frequency` TEXT COMMENT 'lms_login_frequency',
    `resource_access_count` TEXT COMMENT 'resource_access_count',
    `assignment_submission_rate` TEXT COMMENT 'assignment_submission_rate',
    `classroom_temperature` TEXT COMMENT 'classroom_temperature',
    `noise_level` TEXT COMMENT 'noise_level',
    `air_quality_index` TEXT COMMENT 'air_quality_index',
    `study_duration_minutes` TEXT COMMENT 'study_duration_minutes',
    `session_gap_days` TEXT COMMENT 'session_gap_days',
    `heart_rate` TEXT COMMENT 'heart_rate',
    `focus_level` TEXT COMMENT 'focus_level',
    `teaching_effectiveness` TEXT COMMENT 'teaching_effectiveness',
    `target_class` TEXT COMMENT 'target_class'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='学生物联网课程学习数据';

